async def calculate_next_run(schedule: Schedule, schedule_times: list = None) -> datetime:
    """Calculate next execution time for schedule."""
    if schedule.schedule_type == 'interval':
        return datetime.now() + timedelta(minutes=schedule.interval_minutes)

    elif schedule.schedule_type == 'daily_count':
        now = datetime.now()
        next_time = None

        for st in schedule_times:
            scheduled = now.replace(hour=st['hour'], minute=st['minute'])
            if scheduled > now:
                next_time = scheduled
                break

        if not next_time:
            next_time = now.replace(hour=schedule_times[0]['hour'], 
                                   minute=schedule_times[0]['minute'])
            next_time += timedelta(days=1)

        return next_time

