class ConversationState:
    def __init__(self):
        self.states = {}  # user_id -> {state, data, timestamp}

    async def set(self, user_id, state, data=None):
        self.states[user_id] = {'state': state, 'data': data, 'timestamp': time.time()}

    async def get(self, user_id):
        if user_id not in self.states:
            return None
        if time.time() - self.states[user_id]['timestamp'] > 300:  # 5 min timeout
            del self.states[user_id]
            return None
        return self.states[user_id]

    async def clear(self, user_id):
        if user_id in self.states:
            del self.states[user_id]
